export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const cellKey = (x: number, y: number): string => `${x},${y}`;
  const aliveCells = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const countNeighbors = (x: number, y: number): number => {
    let neighborCount = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (aliveCells.has(cellKey(x + dx, y + dy))) neighborCount++;
      }
    }
    return neighborCount;
  };

  const candidateCells = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const nx = x + dx;
        const ny = y + dy;
        candidateCells.set(cellKey(nx, ny), [nx, ny]);
      }
    }
  }

  const nextCells: Cell[] = [];
  for (const [key, [x, y]] of candidateCells) {
    const neighborCount = countNeighbors(x, y);
    const isAlive = aliveCells.has(key);
    if (isAlive && (neighborCount === 2 || neighborCount === 3)) {
      nextCells.push([x, y]);
    } else if (!isAlive && neighborCount === 3) {
      nextCells.push([x, y]);
    }
  }
  return nextCells;
}

